initialCss:
body {
  font-family: sans-serif;
  background: #f0f4f8;
  display: flex;
  justify-content: center;
  align-items: center;
  min-height: 100vh;
  margin: 0;
}
#profile-card {
  background: #fff;
  border-radius: 12px;
  box-shadow: 0 4px 20px rgba(0,0,0,0.1);
  padding: 30px;
  text-align: center;
  max-width: 300px;
  width: 100%;
}
#profile-img {
  width: 90px;
  height: 90px;
  border-radius: 50%;
  object-fit: cover;
  margin-bottom: 12px;
}
#profile-name {
  margin: 0 0 8px;
  color: #1a202c;
}
#profile-bio {
  color: #718096;
  font-size: 14px;
}
#contact-btn {
  margin-top: 16px;
  padding: 10px 24px;
  background: #4f46e5;
  color: #fff;
  border: none;
  border-radius: 8px;
  cursor: pointer;
  font-size: 14px;
}

