solutionCss:
body {
  margin: 0;
  font-family: sans-serif;
}
#main-nav {
  display: flex;
  justify-content: space-between;
  align-items: center;
  background: #1e293b;
  padding: 16px 32px;
}
#logo {
  font-size: 22px;
  font-weight: bold;
  color: #fff;
}
#nav-links {
  list-style: none;
  margin: 0;
  padding: 0;
  display: flex;
  gap: 24px;
}
#nav-links a {
  text-decoration: none;
  color: #cbd5e1;
  transition: color 0.2s;
}
#nav-links a:hover {
  color: #6366f1;
}
